/* SQL ID : orgCodeDAO.selectOrgCodeList 설 명 : 리스트 */ SELECT ORG_ID
, CMMN_CD_ID
, CD , ORG_ID , UP_CD , CD_SEQNO , CDNM , CD_EXPLN
, USEYN , RGTR_ID , (SELECT USERNM FROM TB_LMS_USER WHERE USER_ID = RGTR_ID) AS RGTRNM , REG_DTTM , MDFR_ID , (SELECT USERNM FROM TB_LMS_USER WHERE USER_ID = MDFR_ID) AS MOD_NM , MOD_DTTM
FROM TB_LMS_CMMN_CD A WHERE 1 = 1 AND UP_CD = #{upCd}
AND ( LOWER(CD) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(CDNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND USEYN = #{useYn}
AND ORG_ID = #{orgId}
AND CD = #{cd}
ORDER BY CD_SEQNO ASC

