       ORG_ID
     , UP_CD
     , CD
     , CDNM
     , CD_SEQNO
     , CD_EXPLN
     , CD_OPTN
     , USEYN
     , RGTR_ID
     , FRST_INQ_DTTM
     , MDFR_ID
     , MOD_DTTM
) VALUES (
       #{orgId}
     , #{upCd}
     , #{cd}
     , #{cdnm}
     , #{cdSeq}
     , #{cdExpln}
     , #{codeOptn}
     , #{useYn}
     , #{rgtrId}
     , FN_DTTM()
     , #{mdfrId}
     , FN_DTTM()
)

